import json

D = lambda i,t,s,e,n,c,nx: {"id":i,"text":t,"speaker":"我","avatar":"厂","score":s,"triggeredEvent":e,"historicalNote":n,"consequence":c,"nextActId":nx}
A = lambda i,t,k,tm,s,n,dls: {"id":i,"title":t,"isKeyAct":k,"timeMarker":tm,"sceneDescription":s,"npcDialogues":n,"dialogues":dls}
N = lambda sp,tx,av: {"speaker":sp,"text":tx,"avatar":av}

acts = []

# 4
acts.append(A("act-4","工厂制度",False,"1785年",
"蒸汽机安装完成后，你的工厂进入了全新的发展阶段。工人们必须遵守严格的作息时间，在机器的轰鸣中日复一日地劳作。作为工厂主，你需要建立一套完善的管理制度来确保生产效率。",
[N("工头罗伯特","老板，这些工人以前都是手工劳动者，自由散漫惯了。要让他们遵守工厂纪律，可得下点功夫。","罗"),N("老工人詹姆斯","我们习惯了自己安排时间，现在每天要工作14个小时，实在太累了。","詹")],
[D("d1","建立严格的工厂纪律，实行三班制，让机器24小时运转。",90,"你建立了严格的工厂管理制度，实行三班制轮换。工厂24小时不停运转，产量大幅提升，成为曼彻斯特效率最高的工厂之一。","工厂制度是工业革命的重要产物。阿克莱特最早建立了严格的工厂纪律，工人必须按时上下班，遵守统一的作息时间。三班制的实行大大提高了设备利用率。","制度建立，效率大增","act-5"),
D("d2","我要建立奖惩制度，表现好的奖励，偷懒的惩罚。",82,"你建立了明确的奖惩制度，表现优秀的工人可以获得奖金，而迟到早退的则会被扣工资。工人们的积极性有所提高。","工业革命时期，工厂主采用各种手段提高工人的劳动效率。奖惩制度是最常见的管理方式之一，对提高生产效率起到了一定作用。","奖惩分明，积极性提高","act-5"),
D("d3","对工人好一点，改善工作条件，工人满意了效率自然高。",85,"你决定实行人性化管理，适当缩短工时，改善工作环境。工人们很感激，工作效率反而比以前更高了。","欧文在新拉纳克工厂的实践证明，改善工人待遇可以提高生产效率。欧文是19世纪初著名的空想社会主义者，他的工厂管理实验影响深远。","人性化管理，效率提升","act-5"),
D("d4","延长工作时间，从早上5点到晚上9点，最大化产出。",62,"你把工作时间延长到16小时。短期内产量确实增加了，但工人们疲惫不堪，事故频发，产品质量也下降了。","工业革命初期，工人的工作时间非常长，通常每天14-16小时。过度劳动导致了严重的健康问题和安全事故，这也是后来工人运动的重要起因。","工时过长，事故频发","act-4b"),
D("d5","我要引入计件工资制，干得多拿得多，激励工人努力工作。",88,"你实行了计件工资制，工人的收入与产量直接挂钩。工人们的积极性被充分调动起来，工厂产量大幅提升。","计件工资制是工业革命时期普遍采用的工资制度。它将工人的收入与劳动成果直接挂钩，能够有效激励工人提高劳动生产率。","计件工资，产量大增","act-5"),
D("d6","雇佣监工来监督工人，谁敢偷懒就处罚谁。",70,"你雇佣了几名监工，专门监督工人的劳动。工人们在监督下不敢偷懒，但工作压力很大，人员流动率很高。","工业革命初期，监工制度非常普遍。监工负责监督工人的劳动，维持工厂纪律。但这种制度也加剧了劳资矛盾。","监工制度，压力增大","act-5"),
D("d7","我要对工人进行培训，让他们掌握更熟练的技能。",84,"你建立了工人培训制度，新工人必须经过培训才能上岗。熟练工人的比例提高后，产品质量和生产效率都有明显改善。","工业革命时期，技能培训主要通过学徒制进行。但随着工厂规模扩大，一些有远见的工厂主开始建立自己的培训体系。","技能培训，质量提升","act-5"),
D("d8","尽量压低工人工资，降低成本，提高利润空间。",60,"你大幅压低工人工资，利润确实增加了。但工人们怨声载道，很多技术工人跳槽到了待遇更好的工厂。","工业革命初期，工人工资普遍很低。但过低的工资会导致工人不满和人才流失，从长远来看不利于企业发展。","低薪策略，人才流失","act-4b"),
D("d9","我要建立工厂食堂和宿舍，解决工人的后顾之忧。",76,"你在工厂附近建立了食堂和宿舍，工人们不用再为吃住发愁。虽然增加了成本，但工人的稳定性大大提高了。","一些有远见的工厂主会为工人提供住宿和伙食。这既是出于人道考虑，也是为了保证劳动力的稳定供应。","食宿配套，工人稳定","act-5")]))

# 4b
acts.append(A("act-4b","工人不满",False,"1786年",
"由于你实行的高压政策，工人们的不满情绪日益积累。工厂里弥漫着压抑的气氛，随时可能爆发冲突。你必须想办法缓解工人的不满，否则后果不堪设想。",
[N("工人代表山姆","老板，我们实在太累了。每天工作16个小时，工资还这么低，大家都撑不住了。","山"),N("工头罗伯特","老板，我看工人们情绪不对头，可能要出事。您是不是考虑调整一下政策？","罗")],
[D("d1","我愿意做出让步，缩短工时，提高工资，大家好好商量。",88,"你主动做出让步，同意缩短工时和提高工资。工人们的不满情绪得到缓解，工厂恢复了正常生产。这次事件也让你认识到善待工人的重要性。","工业革命时期，工人阶级为了改善自身处境进行了不懈的斗争。一些有远见的工厂主也意识到，适当改善工人待遇有利于生产的稳定进行。","做出让步，矛盾缓解","act-5"),
D("d2","坚决不让步，他们不干有的是人干，不能惯坏了他们。",60,"你态度强硬，拒绝了工人的要求。几天后，一场罢工爆发了，工厂被迫停产。损失远远超过了让步的成本。","工业革命初期，工人罢工事件不断增加。资本家的残酷剥削激起了工人阶级的强烈反抗，工人运动逐渐兴起。","态度强硬，罢工爆发","act-5"),
D("d3","解雇领头闹事的人，杀鸡儆猴，看谁还敢捣乱。",63,"你解雇了几名带头闹事的工人。其他人虽然表面上不敢反抗了，但心中的不满更深了，工作效率也更低了。","工业革命时期，工厂主经常用解雇的手段来压制工人的反抗。但这只能暂时压制矛盾，不能从根本上解决问题。","解雇领头人，矛盾加深","act-5"),
D("d4","我要和工人代表坐下来好好谈，听听他们的诉求。",85,"你邀请工人代表进行谈判，认真听取了他们的诉求。经过协商，双方达成了都能接受的方案，工厂的氛围改善了很多。","劳资谈判是解决劳资矛盾的重要方式。随着工人运动的发展，资本家逐渐认识到谈判比镇压更有利于问题的解决。","劳资谈判，达成共识","act-5"),
D("d5","设立意见箱，让工人有渠道反映问题，及时处理。",78,"你在工厂设立了意见箱，鼓励工人反映问题。虽然很多意见一时难以解决，但工人的不满情绪有了宣泄的渠道。","建立沟通渠道是缓解劳资矛盾的有效方法。让工人有地方说话，比把不满压在心里要好得多。","意见渠道，情绪宣泄","act-5"),
D("d6","我要改善工厂的安全设施，减少工伤事故。",82,"你投入资金改善了工厂的安全设施，工伤事故明显减少。工人们感受到了你的诚意，工作积极性也提高了。","工业革命时期，工厂的安全条件很差，工伤事故频发。一些有良知的工厂主开始重视安全生产，这也是工厂管理的进步。","改善安全，事故减少","act-5"),
D("d7","成立工厂委员会，让工人参与管理，增强归属感。",90,"你成立了工厂委员会，吸收工人代表参与管理。工人们有了参与感和归属感，工厂的凝聚力大大增强，生产效率也随之提高。","让工人参与管理是一种先进的管理理念。虽然在工业革命时期并不普遍，但一些有远见的企业家已经开始尝试这种模式。","工人参与，凝聚力增强","act-5"),
D("d8","找些打手来，谁敢闹事就教训谁，看他们老实不老实。",62,"你雇佣了打手来对付闹事的工人。暴力镇压确实让工人不敢反抗了，但工厂里弥漫着恐惧的气氛，人人自危。","工业革命时期，资本家有时会使用暴力手段镇压工人反抗。但这种做法只会加剧阶级对立，最终损害的是整个社会的稳定。","暴力镇压，人人自危","act-5"),
D("d9","我要办一所工人子弟学校，让工人的孩子有学上。",86,"你出资办了一所工人子弟学校，让工人的子女能够接受教育。工人们非常感激，工作更加努力了，工厂的稳定性也大大提高了。","工业革命时期，工人的受教育程度普遍很低。一些有远见的工厂主开始重视工人子女的教育，这不仅是人道关怀，也有利于提高工人素质。","兴办学校，人心稳定","act-5")]))

# 5
acts.append(A("act-5","招募工人",False,"1788年",
"工厂规模不断扩大，你需要招募更多的工人。然而，熟练工人供不应求，很多从农村来的人缺乏技能。你需要制定招募和培训策略，确保工厂有足够的合格劳动力。",
[N("工头罗伯特","老板，现在熟练工人太难找了。从农村来的人什么都不会，得从头教起，太费时间了。","罗"),N("农村来的姑娘玛丽","老爷，我从乡下来的，什么活都能干，只要能给口饭吃就行。","玛")],
[D("d1","我要建立学徒制度，让熟练工人带徒弟，培养自己的技术队伍。",90,"你建立了完善的学徒制度，每个熟练工人带几个徒弟。几年后，你的工厂培养出了一批技术熟练的工人，成为企业发展的骨干力量。","学徒制是工业革命时期培养技术工人的主要方式。通过师傅带徒弟的方式，大量农村青年掌握了工业生产技能，成为产业工人。","学徒制度，技术传承","act-6"),
D("d2","高薪挖别的工厂的熟练工人，快速组建技术队伍。",78,"你用高薪从其他工厂挖来了一批熟练工人。工厂很快运转起来，但也引起了其他工厂主的不满，行业内竞争更加激烈。","工业革命时期，熟练工人是稀缺资源。工厂主之间经常互相挖角，这也导致了工人工资的上涨和人员流动的频繁。","高薪挖角，快速上手","act-6"),
D("d3","大量招收女工，她们工资低，而且手巧适合纺织工作。",82,"你大量招收女工，她们的工资虽然低于男工，但心灵手巧，很适合纺织工作。女工成为你工厂的主力军，成本也降低了不少。","工业革命时期，大量妇女和儿童进入工厂工作。她们工资低廉，但在纺织等行业发挥了重要作用，也为妇女解放创造了条件。","女工为主，成本降低","act-6"),
D("d4","从孤儿院招收童工，他们听话又便宜，还不用给多少工资。",60,"你从孤儿院招收了一批童工。他们虽然工资低廉，但体力有限，而且容易生病。社会上也开始出现批评你使用童工的声音。","工业革命初期，童工被广泛使用。很多工厂从孤儿院招收学徒，这些孩子每天工作很长时间，待遇极差，身心健康受到严重损害。","使用童工，社会批评","act-5b"),
D("d5","我要和周边农村建立联系，定期招收年轻农民。",85,"你和周边的农村建立了长期合作关系，定期招收年轻农民进厂工作。稳定的劳动力来源保证了工厂的持续发展。","工业革命时期，大量农村人口涌入城市，成为产业工人的主要来源。工厂主们通过各种方式从农村招募工人，满足工业发展的劳动力需求。","农村招募，来源稳定","act-6"),
D("d6","设立奖金制度，介绍工人进厂的给奖励，发动大家帮忙招人。",76,"你设立了介绍奖金，鼓励工人介绍亲戚朋友进厂。通过工人的人脉网络，你很快招到了足够的人手，而且新工人的稳定性也比较高。","工人介绍是工业革命时期常见的招工方式。通过熟人介绍进厂的工人，往往更有归属感，也更容易适应工厂生活。","介绍奖励，人脉招工","act-6"),
D("d7","我要建立工人培训学校，系统地培训新工人。",88,"你建立了工人培训学校，新工人必须经过系统培训才能上岗。虽然前期投入大，但培训后的工人技术水平高，生产效率也更高。","系统的工人培训是工业发展到一定阶段的产物。随着工厂规模扩大和技术进步，传统的学徒制已经不能满足需求，专门的培训学校应运而生。","培训学校，系统培养","act-6"),
D("d8","尽量压低工资，反正有的是人想干活，不愁招不到人。",65,"你压低了工资标准，虽然来应聘的人不少，但都是些没技术的人。熟练工人都去了待遇更好的工厂，你工厂的技术水平越来越低。","低工资虽然能降低成本，但也会导致人才流失。在工业革命时期，熟练工人是稀缺资源，他们会流向待遇更好的企业。","低薪招工，质量下降","act-5b"),
D("d9","我要改善工人待遇，提供食宿，吸引更多人来工作。",84,"你提高了工人待遇，还提供免费食宿。消息传开后，很多人慕名而来，你可以从中挑选最优秀的工人。","优厚的待遇是吸引人才的有效手段。在工业革命时期，一些有远见的工厂主通过提高待遇来吸引和留住优秀工人。","优厚待遇，人才聚集","act-6")]))

# 5b
acts.append(A("act-5b","劳动力短缺",False,"1789年",
"由于待遇太差，你的工厂面临严重的劳动力短缺问题。熟练工人纷纷跳槽，新招的工人又技术不熟练。工厂产量下降，订单完不成，你陷入了两难的境地。",
[N("工头罗伯特","老板，再这样下去不行啊。熟练工人都快走光了，剩下的人也没心思干活。","罗"),N("账房托马斯","老板，这个月的订单又完不成了，客户都在催货。再不解决人手问题，我们就要违约了。","托")],
[D("d1","立刻提高工人工资，改善待遇，把流失的工人请回来。",90,"你果断决定提高工人工资，改善工作条件。消息传开后，不仅流失的工人回来了，还吸引了更多技术工人。工厂很快恢复了元气。","在工业革命时期，劳动力市场的竞争逐渐发挥作用。待遇好的工厂能够吸引和留住优秀工人，而苛刻的工厂则会面临用工荒。","提高待遇，工人回归","act-6"),
D("d2","去更远的农村招工，那里的人要求低，肯定愿意来。",70,"你派人去更远的农村招工，招来了一批吃苦耐劳的农民。虽然他们技术不熟练，但肯干肯学，慢慢也能顶上手了。","工业革命时期，劳动力的流动范围不断扩大。工厂主们从越来越远的地方招募工人，促进了人口的流动和城市化进程。","远地招工，补充人力","act-6"),
D("d3","我要引进更多机器，用机器代替人力，减少对工人的依赖。",88,"你决定加大技术投入，引进更多先进机器，提高自动化水平。虽然机器投入大，但大大减少了对人工的依赖，长期来看更划算。","技术进步是解决劳动力短缺的根本途径。随着机器的不断改进，对工人数量的需求相对减少，对工人素质的要求则不断提高。","机器换人，减少依赖","act-6"),
D("d4","强迫工人加班加点，完不成任务就扣工资。",60,"你强迫工人加班加点，完不成任务就扣工资。工人们怨声载道，罢工一触即发，工厂随时可能陷入更大的危机。","强制劳动不仅不道德，而且效率低下。工业革命的历史证明，善待工人、提高工人积极性才是提高生产效率的正道。","强制加班，矛盾激化","act-6"),
D("d5","和其他工厂主联合起来，约定互不挖角，稳定工人市场。",75,"你联合了几家工厂主，约定互不挖角，统一工资标准。这虽然稳定了工人市场，但也引起了工人的不满，认为这是资本家的联合剥削。","工业革命时期，资本家之间既有竞争也有联合。他们有时会联合起来对付工人，压低工资，这加剧了阶级对立。","厂主联合，稳定市场","act-6"),
D("d6","建立工龄工资制度，干得越久工资越高，留住老工人。",85,"你建立了工龄工资制度，工人在厂工作时间越长，工资越高。老工人的流失率大大降低，他们丰富的经验也带动了新工人的成长。","建立合理的薪酬制度是留住人才的关键。工龄工资就是其中一种有效的方式，它能够鼓励工人长期为企业服务。","工龄工资，留住老工人","act-6"),
D("d7","我要设立奖励基金，对表现优秀的工人给予重奖。",82,"你设立了奖励基金，每月评选优秀工人给予重奖。工人们的积极性被调动起来，形成了比学赶超的良好氛围。","物质奖励是激励工人的重要手段。在工业革命时期，各种奖金制度逐渐建立起来，对提高生产效率起到了积极作用。","重奖优秀，积极性高","act-6"),
D("d8","干脆缩小生产规模，反正人手不够，少生产点少赔点。",66,"你决定缩小生产规模，裁减人员，减少订单。虽然降低了风险，但你的市场份额也在萎缩，企业发展陷入停滞。","面对困难，退缩和保守虽然能暂时自保，但从长远来看会丧失发展机遇。在工业革命的浪潮中，不进则退。","收缩规模，发展停滞","act-6"),
D("d9","我要去爱尔兰招工，那里贫困，工人工资要求低。",72,"你派人去爱尔兰招募了一批工人。他们工资要求低，能吃苦耐劳，但也带来了文化差异和管理上的问题。","工业革命时期，爱尔兰向英国本土输送了大量劳动力。爱尔兰工人吃苦耐劳，工资要求低，在英国工业发展中发挥了重要作用。","爱尔兰招工，成本降低","act-6")]))

# 6
acts.append(A("act-6","童工困境",False,"1790年",
"随着工厂规模扩大，你雇佣了越来越多的童工。这些孩子每天工作十几个小时，待遇很差，经常生病。社会上开始出现批评的声音，议会也有人提出要限制童工。你面临着道义和利益的选择。",
[N("医生克拉克","老板，这些孩子的身体状况很差。长期过度劳动会严重影响他们的身心健康，甚至会缩短寿命。","克"),N("慈善家伊丽莎白","先生，使用童工是不人道的。这些孩子应该在学校里读书，而不是在工厂里做工。","伊")],
[D("d1","我要逐步减少童工，改善他们的待遇，让他们有时间学习。",92,"你决定逐步减少童工数量，改善童工待遇，还办了一所夜校让他们学习。虽然增加了成本，但你的做法赢得了社会的尊重。","工业革命时期，童工问题引起了社会的广泛关注。一些有良知的工厂主开始主动改善童工待遇，限制童工的使用。","减少童工，赢得尊重","act-7"),
D("d2","继续使用童工，这能大幅降低成本，提高竞争力。",62,"你决定继续大量使用童工以降低成本。虽然利润很高，但社会批评越来越多，你的名声也受到了影响。","工业革命初期，童工被广泛使用。但随着社会的进步，人们越来越认识到童工的危害，要求限制童工的呼声也越来越高。","继续用童工，名声受损","act-6b"),
D("d3","我要改善童工的生活和工作条件，至少让他们吃饱穿暖。",78,"你改善了童工的伙食和住宿条件，缩短了他们的工作时间。虽然成本增加了一些，但孩子们的健康状况有所改善。","一些有良知的工厂主虽然也使用童工，但会尽量改善他们的待遇。这虽然不能从根本上解决问题，但也是一种进步。","改善待遇，健康好转","act-7"),
D("d4","只招收年龄大一点的童工，太小的孩子确实不适合做工。",72,"你决定只招收12岁以上的童工，不再使用年幼的孩子。这在一定程度上缓解了社会批评，但仍然没有完全解决问题。","随着社会对童工问题的关注，一些工厂主开始限制童工的年龄。这是一个渐进的过程，直到工厂法颁布后才逐步得到解决。","限制年龄，缓解批评","act-7"),
D("d5","我要办一所学校，让童工在工作之余能够学习读书写字。",88,"你在工厂办了一所学校，让童工在工作之余学习文化知识。虽然每天学习时间不长，但为这些孩子打开了一扇希望之门。","一些有远见的工厂主认识到教育的重要性，开始为工人子女提供教育机会。这不仅是人道关怀，也有利于提高工人的素质。","开办学校，点燃希望","act-7"),
D("d6","把童工安排到相对轻松的岗位，不做太重的活。",75,"你把童工安排到相对轻松的岗位，从事一些简单的辅助性工作。虽然他们仍然工作很长时间，但至少不用干重体力活了。","在工业革命时期，童工通常被安排到适合他们体力的岗位上。但即使是轻松的工作，过长的劳动时间仍然会严重损害他们的健康。","岗位调整，减轻负担","act-7"),
D("d7","这是社会问题，我一个人改变不了什么，还是继续赚钱吧。",65,"你认为童工问题是社会问题，个人无力改变，于是继续大量使用童工。虽然你赚了很多钱，但内心深处总有一些不安。","工业革命时期，童工问题确实是一个复杂的社会问题。它的解决需要政府立法、社会监督和企业自律的共同努力。","只顾赚钱，内心不安","act-6b"),
D("d8","我要带头倡议制定工厂法，用法律来规范童工使用。",90,"你带头倡议制定工厂法，用法律来规范童工的使用。虽然这在短期内会增加成本，但从长远来看有利于社会的进步。","19世纪初，英国开始制定工厂法来限制童工的使用。1833年的工厂法规定了童工的年龄限制和工作时间，这是社会进步的重要标志。","倡议立法，推动进步","act-7"),
D("d9","把童工送回家，宁愿少赚点钱，也不能做亏心事。",85,"你决定把所有童工都送回家，宁愿减少产量和利润，也不愿再做违背良心的事。你的做法赢得了广泛赞誉，也带动了其他工厂主反思。","随着社会的进步，越来越多的人认识到童工的危害。一些有良知的企业家主动停止使用童工，推动了社会风气的转变。","停止用童工，赢得赞誉","act-7")]))

# 6b
acts.append(A("act-6b","丑闻危机",False,"1792年",
"你使用童工的事情被报纸曝光了，引起了社会舆论的强烈谴责。人们纷纷抵制你的产品，工厂的销量大幅下滑。更糟糕的是，议会正在讨论工厂法，你的工厂可能面临调查。",
[N("律师威廉姆斯","老板，现在舆论对我们非常不利。如果议会通过工厂法，我们的成本会大幅上升。","威"),N("商人亨利","我很抱歉，由于舆论压力，我不得不取消和你的订单。我的客户拒绝购买使用童工的工厂生产的产品。","亨")],
[D("d1","立刻停止使用童工，公开道歉，争取社会的谅解。",90,"你立刻宣布停止使用童工，并公开向社会道歉。你还承诺为这些孩子提供教育机会。虽然损失不小，但你的坦诚赢得了公众的谅解。","面对舆论危机，坦诚认错是最好的策略。工业革命时期，随着公众意识的觉醒，企业的社会责任越来越受到重视。","公开道歉，赢得谅解","act-7"),
D("d2","坚决否认，说这些都是造谣，我是被冤枉的。",60,"你坚决否认使用童工的指责，声称这是竞争对手的造谣。但很快，更多的证据被曝光，你的处境更加被动。","在事实面前，否认和抵赖是徒劳的。工业革命时期，新闻媒体逐渐成为监督社会的重要力量。","坚决否认，更加被动","act-7"),
D("d3","我要请最好的律师，通过法律途径解决这个问题。",72,"你请了最好的律师，准备通过法律途径解决问题。虽然你在法律上可能没有问题，但在道德上你已经输了。","法律途径是解决争议的方式之一，但法律和道德并不总是一致的。有些事情虽然合法，但可能不合情理。","法律途径，道德失分","act-7"),
D("d4","主动联系慈善机构，一起改善童工的处境。",85,"你主动联系了慈善机构，宣布将与他们合作改善童工的处境。你还邀请记者参观工厂，展示你的改进措施。","与社会机构合作是化解危机的有效方式。通过公开透明的方式展示改进，能够重建公众信任。","慈善合作，重建信任","act-7"),
D("d5","把工厂搬到监管不严的地方去，换个地方继续干。",63,"你把工厂搬到了监管不严的偏远地区，继续使用童工。虽然暂时避开了舆论，但问题并没有解决，迟早还会爆发。","逃避不是解决问题的办法。随着社会的进步，监管会越来越严格，逃避只能是暂时的。","搬迁躲避，治标不治本","act-7"),
D("d6","我要转变经营方向，做不需要大量童工的业务。",82,"你决定转变经营方向，投资于不需要大量童工的领域。虽然转型很痛苦，但这是长期可持续发展的道路。","企业转型是应对社会变革的重要策略。随着社会的发展，一些旧的经营模式会被淘汰，企业需要与时俱进。","业务转型，可持续发展","act-7"),
D("d7","游说议员，阻止工厂法通过，维护我们的利益。",68,"你联合其他工厂主游说议员，试图阻止工厂法通过。虽然暂时延缓了立法进程，但历史潮流是不可阻挡的。","工业革命时期，工厂主们为了维护自身利益，经常游说议会反对立法。但随着社会的进步，保护工人权益的立法是大势所趋。","游说议会，延缓立法","act-7"),
D("d8","我要建立行业协会，制定行业规范，主动进行自我约束。",88,"你发起建立了行业协会，制定了行业规范，主动进行自我约束。这不仅化解了危机，还提升了整个行业的形象。","行业自律是化解危机、提升行业形象的有效方式。通过自我约束，既能满足社会期待，又能避免过度监管。","行业自律，提升形象","act-7"),
D("d9","干脆把工厂卖了，这行越来越难做了。",66,"你把工厂卖掉了，带着钱转投其他行业。虽然避开了麻烦，但你也错过了工业革命的大好机遇。","面对困难，选择退出是一种保守的策略。虽然能避免风险，但也可能错失发展机遇。","卖掉工厂，转投他行","act-7")]))

